  tempVector3a.fromArray(arrA);
  tempVector3b.fromArray(arrB);
  tempVector3a.lerp(tempVector3b, t);
  return tempVector3a.toArray();
}

function fb(arrA, t) { // arrA = [1,1,1]
  tempVector3a.fromArray(arrA);
  const arrB = fa([1,1,1], [3,3,3], 0.5); // result [2,2,2]
  tempVector3b.fromArray(arrB);
  tempVector3a.lerp(tempVector3b, t); // expect to lerp [1,1,1] [2,2,2] too, but not.
  return tempVector3a.toArray();
}

console.log( fa([1,1,1], [2,2,2], 0.5) );
console.log( fb([1,1,1], 0.5) );
  
// => [1.5, 1.5, 1.5] // expected
// => [2, 2, 2] // unexpected
```

But if have `Vector3.lerpFlat`, we can avoid this problem, and many conversions:
```
function fa(arrA, arrB, t) {
  THREE.Vector3.lerpFlat(arrA,0,arrA,0,arrB,0,t);
  return arrA;
}

function fb(arrA, t) {
  const arrB = fa([1,1,1], [3,3,3], 0.5);
  THREE.Vector3.lerpFlat(arrA,0,arrA,0,arrB,0,t);
  return arrA;
}

console.log( fa([1,1,1], [2,2,2], 0.5) );
console.log( fb([1,1,1], 0.5) );
  
// => [1.5, 1.5, 1.5] // expected
// => [1.5, 1.5, 1.5] // expected
```

